+#[derive(Hash, PartialEq, Eq)]
+struct EdgeKeyRef<'a> {
+    left: &'a str,
+    right: &'a str,
+}
+
+impl<'a> EdgeKeyRef<'a> {
+    fn new(left: &'a str, right: &'a str) -> Self {
+        if left <= right {
+            Self { left, right }
+        } else {
+            Self {
+                left: right,
+                right: left,
+            }
+        }
+    }
+}
+
+impl<'a> indexmap::Equivalent<EdgeKey> for EdgeKeyRef<'a> {
+    fn equivalent(&self, key: &EdgeKey) -> bool {
+        self.left == key.left && self.right == key.right
+    }
+}
+
